const END = "<!-- eslint-plugin-raula-instruct-end -->";
const AGENTS_FILE = "AGENTS.md";
const REFERENCE_PATH = "./node_modules/eslint-plugin-raula/REFERENCE.md";
const ESLINT_CONFIG_FILES = [
	"eslint.config.js",
